"""
Tag CRUD routes — Variant Sample 1

Design decisions (mutation strategy):
- Uses a lightweight "serializer" approach: each Tag instance is converted
  to a plain dict via a module-level helper function, rather than a class
  method or a marshmallow schema.
- Duplicate detection uses a try/except around db.session.commit() to catch
  IntegrityError from the unique constraint, rather than a pre-check query.
  This is a "let the DB enforce it" strategy that avoids race conditions.
- Deletion cascades by explicitly deleting from the association table first
  (via raw SQL DELETE), then removing the Tag object. This gives explicit
  control over the order of operations rather than relying on SQLAlchemy's
  passive_deletes.
- Request payload is validated with a simple dict-access pattern and
  isinstance checks, keeping dependencies minimal (no extra validation lib).
- Each route handler is intentionally kept short and delegates to small
  private helpers for a clean separation of concerns.
"""

from flask import Blueprint, request, jsonify, g
from sqlalchemy.exc import IntegrityError

from models import Tag, db, article_tags

tag_bp = Blueprint('tag_bp', __name__)


# ---------------------------------------------------------------------------
# Serialization helper
# ---------------------------------------------------------------------------

def _serialize_tag(tag):
    """Convert a Tag ORM object to a plain dictionary."""
    return {"id": tag.id, "name": tag.name}


def _serialize_tags(tags):
    """Convert an iterable of Tag ORM objects to a list of dicts."""
    return [_serialize_tag(t) for t in tags]


def _ok_response(data, status_code=200):
    """Build a standard success JSON response."""
    body = {"status": "ok", "data": data}
    return jsonify(body), status_code


def _error_response(message, status_code=400):
    """Build a standard error JSON response."""
    body = {"status": "error", "message": message}
    return jsonify(body), status_code


# ---------------------------------------------------------------------------
# Validation helper
# ---------------------------------------------------------------------------

def _extract_name(data):
    """
    Extract and validate the 'name' field from request data.

    Returns (name_str, error_response) where exactly one of the two is None.
    If name is valid, error_response is None; otherwise name_str is None.
    """
    if data is None:
        return None, _error_response("Request body must be JSON", 400)

    name = data.get("name")
    if name is None:
        return None, _error_response("Field 'name' is required", 400)

    if not isinstance(name, str) or name.strip() == "":
        return None, _error_response("Field 'name' must be a non-empty string", 400)

    return name.strip(), None


# ---------------------------------------------------------------------------
# Routes
# ---------------------------------------------------------------------------

@tag_bp.route("/tags", methods=["POST"])
def create_tag():
    """Create a new tag. 409 on duplicate name, 400 if name missing/blank."""
    payload = request.get_json(silent=True)
    name, err = _extract_name(payload)
    if err:
        return err

    tag = Tag(name=name)
    db.session.add(tag)

    try:
        db.session.commit()
    except IntegrityError:
        db.session.rollback()
        return _error_response(f"Tag '{name}' already exists", 409)

    return _ok_response(_serialize_tag(tag), 201)


@tag_bp.route("/tags", methods=["GET"])
def list_tags():
    """Return all tags as a JSON array."""
    tags = Tag.query.order_by(Tag.id.asc()).all()
    return _ok_response(_serialize_tags(tags))


@tag_bp.route("/tags/<int:tag_id>", methods=["PUT"])
def update_tag(tag_id):
    """Update a tag's name. 404 if not found, 409 on duplicate name."""
    tag = Tag.query.get(tag_id)
    if tag is None:
        return _error_response(f"Tag with id {tag_id} not found", 404)

    payload = request.get_json(silent=True)
    name, err = _extract_name(payload)
    if err:
        return err

    tag.name = name

    try:
        db.session.commit()
    except IntegrityError:
        db.session.rollback()
        return _error_response(f"Tag '{name}' already exists", 409)

    return _ok_response(_serialize_tag(tag))


@tag_bp.route("/tags/<int:tag_id>", methods=["DELETE"])
def delete_tag(tag_id):
    """Delete a tag and all its article-tag associations. 404 if not found."""
    tag = Tag.query.get(tag_id)
    if tag is None:
        return _error_response(f"Tag with id {tag_id} not found", 404)

    # Explicitly remove association rows first, then delete the tag.
    # Using raw SQL for the association table because it's a plain
    # db.Table (not a model class), so we can't call .delete() on it
    # through the ORM in a single chained call easily.
    db.session.execute(
        article_tags.delete().where(article_tags.c.tag_id == tag_id)
    )
    db.session.delete(tag)
    db.session.commit()

    return _ok_response({"message": "Tag deleted"})

