"""
T2 Blog -- Article Routes (Sample 2: Class-based ResponseBuilder + explicit validation)

Design decisions for this variant:
- ResponseBuilder: a lightweight stateful builder class encapsulates response
  construction. Unlike the pure-function serialization helpers in the tag routes,
  this provides a composable API (build_success, build_error) and keeps the
  response contract centralized in one place.
- Validator class: groups all input validation logic as static methods rather
  than standalone helper functions. This makes it easy to add new validations
  without proliferating top-level functions.
- SQLAlchemy 2.0 select() queries with explicit `is not None` checks on
  scalars().first() results, avoiding the legacy Model.query API entirely.
- Route handlers are thin wrappers that call into service-layer helper functions,
  each of which returns a ResponseBuilder result directly.
"""

from flask import Blueprint, request, jsonify
from sqlalchemy import select

from app import db
from models import Article

article_bp = Blueprint('article_bp', __name__)


# ---------------------------------------------------------------------------
# Response Builder (class-based, stateful construction)
# ---------------------------------------------------------------------------

class ResponseBuilder:
    """
    Centralizes response formatting into a single class.

    Instead of scattered jsonify({"status": "ok", ...}) calls, every endpoint
    constructs its response through this builder, guaranteeing a uniform shape.
    """

    def __init__(self):
        self._status = "ok"
        self._data = None
        self._message = None
        self._http_code = 200

    def success(self, data, http_code=200):
        """Build a successful response with the given data payload."""
        self._status = "ok"
        self._data = data
        self._http_code = http_code
        return self

    def error(self, message, http_code=400):
        """Build an error response with a descriptive message."""
        self._status = "error"
        self._message = message
        self._http_code = http_code
        return self

    def build(self):
        """Materialize the response as a (jsonify, status_code) tuple."""
        body = {"status": self._status}
        if self._message is not None:
            body["message"] = self._message
        if self._data is not None:
            body["data"] = self._data
        return jsonify(body), self._http_code


# ---------------------------------------------------------------------------
# Validator (class-based, static validation methods)
# ---------------------------------------------------------------------------

class ArticleValidator:
    """
    Groups all input validation for article endpoints.

    Using a class rather than standalone functions keeps the validation
    namespace tidy and makes it trivial to extend with new checks.
    """

    REQUIRED_FIELDS = ("title", "body")

    @staticmethod
    def validate_create_payload(payload):
        """
        Validate the JSON payload for article creation.

        Returns:
            (ResponseBuilder, None) if validation failed (caller returns it)
            (None, dict)             if validation passed, with cleaned fields
        """
        if not isinstance(payload, dict) or not payload:
            return ResponseBuilder().error("Request body must be a JSON object", 400), None

        missing = [f for f in ArticleValidator.REQUIRED_FIELDS if f not in payload]
        if missing:
            return ResponseBuilder().error(
                f"Missing required fields: {', '.join(missing)}", 400
            ), None

        return None, payload


# ---------------------------------------------------------------------------
# Serialization (standalone, returns plain dict)
# ---------------------------------------------------------------------------

def serialize_article(article: Article) -> dict:
    """Convert an Article ORM object to a plain dictionary."""
    return {
        "id": article.id,
        "title": article.title,
        "body": article.body,
    }


# ---------------------------------------------------------------------------
# Service-layer helpers
# ---------------------------------------------------------------------------

def _create_article(payload: dict):
    """Create a new article from validated payload. Returns a ResponseBuilder."""
    article = Article(title=payload["title"], body=payload["body"])
    db.session.add(article)
    db.session.commit()

    return ResponseBuilder().success(serialize_article(article), 201).build()


def _list_articles():
    """Return all articles as a list. Returns a ResponseBuilder."""
    articles = db.session.scalars(
        select(Article).order_by(Article.id)
    ).all()

    return ResponseBuilder().success(
        [serialize_article(a) for a in articles], 200
    ).build()


def _get_article(article_id: int):
    """Fetch a single article by ID. Returns a ResponseBuilder."""
    article = db.session.scalars(
        select(Article).where(Article.id == article_id)
    ).first()

    if article is None:
        return ResponseBuilder().error("Article not found", 404).build()

    return ResponseBuilder().success(serialize_article(article), 200).build()


# ---------------------------------------------------------------------------
# Route handlers (thin -- delegate to service helpers)
# ---------------------------------------------------------------------------

@article_bp.route("/articles", methods=["POST"])
def create_article():
    """POST /articles -- Create a new article."""
    payload = request.get_json(silent=True) or {}

    validation_error, cleaned = ArticleValidator.validate_create_payload(payload)
    if validation_error:
        return validation_error.build()

    return _create_article(cleaned)


@article_bp.route("/articles", methods=["GET"])
def list_articles():
    """GET /articles -- List all articles."""
    return _list_articles()


@article_bp.route("/articles/<int:article_id>", methods=["GET"])
def get_article(article_id):
    """GET /articles/<id> -- Retrieve a single article."""
    return _get_article(article_id)

