  filtering by tag_id uses a subquery on the association table.  These two
  different SQL strategies demonstrate alternative composition approaches.
- The list endpoint (`GET /articles`) has optional query parameter handling
  built into the service method, keeping the route handler thin.
- All business methods return Result objects; the route layer uses _respond()
  to adapt to HTTP responses (single-point coupling, heritage pattern).
"""

from dataclasses import dataclass
from typing import Any, Optional

from flask import Blueprint, request, jsonify
from sqlalchemy import select, insert, delete as sa_delete

from app import db
from models import Article, Tag, article_tags

article_bp = Blueprint('article_bp', __name__)


# ---------------------------------------------------------------------------
# Result type -- pure data, no Flask dependency (heritage from Sample 1)
# ---------------------------------------------------------------------------

@dataclass
class Result:
    """Encapsulates the outcome of a business-logic operation.

    Business helpers return Result objects; only the route layer converts
    them to HTTP responses.  This keeps the core logic testable without Flask.
    """
    ok: bool
    status_code: int
    data: Any = None
    message: str = ""


# ---------------------------------------------------------------------------
# Response adapter -- single point of Flask coupling (heritage from Sample 1)
# ---------------------------------------------------------------------------

def _respond(result: Result):
    """Convert a Result into a Flask JSON response."""
    if result.ok:
        body = {"status": "ok", "data": result.data}
    else:
        body = {"status": "error", "message": result.message}
    return jsonify(body), result.status_code


# ---------------------------------------------------------------------------
# Serialization helpers -- centralized for consistent response shapes
# ---------------------------------------------------------------------------

def _serialize_article(article: Article) -> dict:
    """Convert an Article ORM object to a plain dict."""
    return {"id": article.id, "title": article.title, "body": article.body}


def _serialize_articles(articles) -> list:
    """Convert an iterable of Article objects to a list of dicts."""
    return [_serialize_article(a) for a in articles]


def _serialize_tag(tag: Tag) -> dict:
    """Convert a Tag ORM object to a plain dict."""
    return {"id": tag.id, "name": tag.name}


# ---------------------------------------------------------------------------
# Input validation -- accumulates all field errors (heritage from Sample 1)
# ---------------------------------------------------------------------------

class Validator:
    """Accumulates validation errors for a request payload.

    Unlike simple early-return validation, this collects every missing/invalid
    field so the client gets a comprehensive error message in one round trip.
    """

    def __init__(self, payload: Optional[dict]):
        self._payload = payload or {}
        self._errors: list[str] = []

    def require_string(self, field: str) -> Optional[str]:
        """Check that *field* is present and is a non-empty string.

        Returns the stripped value on success, or None (and records an error).
        """
        value = self._payload.get(field)
        if value is None:
            self._errors.append(f"'{field}' is required")
            return None
        if not isinstance(value, str) or not value.strip():
            self._errors.append(f"'{field}' must be a non-empty string")
            return None
        return value.strip()

    def require_list_of_ints(self, field: str) -> Optional[list[int]]:
        """Check that *field* is present and is a non-empty list of integers.

        Returns the list on success, or None (and records an error).
        """
        value = self._payload.get(field)
        if value is None:
            self._errors.append(f"'{field}' is required")
            return None
        if not isinstance(value, list) or len(value) == 0:
            self._errors.append(f"'{field}' must be a non-empty list")
            return None
        if not all(isinstance(v, int) for v in value):
            self._errors.append(f"'{field}' must contain only integers")
            return None
        return value

    def to_result(self) -> Optional[Result]:
        """Return an error Result if any errors were collected, else None."""
        if self._errors:
            return Result(
                ok=False,
                status_code=400,
                message="; ".join(self._errors),
            )
        return None


# ---------------------------------------------------------------------------
# Article Service -- groups all article business logic in a stateless class
# ---------------------------------------------------------------------------

class ArticleService:
    """Stateless service encapsulating all article-related operations.

    This variant groups related business logic into a service class rather
    than standalone module-level functions.  Every method returns a Result
    to maintain the heritage pattern of decoupled business logic.
    """

    # --- CRUD ---

    @staticmethod
    def create(title: str, body: str) -> Result:
        """Persist a new article and return it."""
        article = Article(title=title, body=body)
        db.session.add(article)
        db.session.commit()
        return Result(ok=True, status_code=201, data=_serialize_article(article))

    @staticmethod
    def list_all() -> Result:
        """Fetch every article, ordered by id ascending."""
        stmt = select(Article).order_by(Article.id)
        articles = db.session.execute(stmt).scalars().all()
        return Result(ok=True, status_code=200, data=_serialize_articles(articles))

    @staticmethod
    def get_by_id(article_id: int) -> Result:
        """Fetch a single article by primary key using db.session.get()."""
        article = db.session.get(Article, article_id)
        if article is None:
            return Result(ok=False, status_code=404, message="Article not found")
        return Result(ok=True, status_code=200, data=_serialize_article(article))

    # --- Tag binding ---

    @staticmethod
    def bind_tags(article_id: int, tag_ids: list[int]) -> Result:
        """Bind a list of tags to an article via the association table.

        Uses explicit INSERT on article_tags, inserting only rows that don't
        already exist to avoid integrity errors on duplicate bindings.
        """
        article = db.session.get(Article, article_id)
        if article is None:
            return Result(ok=False, status_code=404, message="Article not found")

        # Verify all tag_ids exist before inserting anything
        existing_tags = db.session.scalars(
            select(Tag).where(Tag.id.in_(tag_ids))
        ).all()
        existing_ids = {t.id for t in existing_tags}

        for tid in tag_ids:
            if tid not in existing_ids:
                return Result(
                    ok=False,
                    status_code=400,
                    message=f"Tag with id {tid} not found",
                )

        # Insert bindings that don't already exist (idempotent)
        already_bound = db.session.scalars(
            select(article_tags.c.tag_id).where(
                article_tags.c.article_id == article_id,
                article_tags.c.tag_id.in_(tag_ids),
            )
        ).all()

        new_ids = [tid for tid in tag_ids if tid not in set(already_bound)]
        if new_ids:
            db.session.execute(
                insert(article_tags).values(
                    [{"article_id": article_id, "tag_id": tid} for tid in new_ids]
                )
            )
            db.session.commit()

        return Result(ok=True, status_code=200, data={"message": "Tags bound successfully"})

    @staticmethod
    def get_tags(article_id: int) -> Result:
        """Get all tags bound to an article.

        Uses a JOIN query through the association table.
        """
        article = db.session.get(Article, article_id)
        if article is None:
            return Result(ok=False, status_code=404, message="Article not found")

        stmt = (
            select(Tag)
            .join(article_tags, article_tags.c.tag_id == Tag.id)
            .where(article_tags.c.article_id == article_id)
            .order_by(Tag.id)
        )
        tags = db.session.execute(stmt).scalars().all()
        return Result(ok=True, status_code=200, data=[_serialize_tag(t) for t in tags])

    @staticmethod
    def unbind_tag(article_id: int, tag_id: int) -> Result:
        """Remove the association between an article and a tag.

        Uses explicit sa_delete on the association table for cascade control.
        """
        article = db.session.get(Article, article_id)
        if article is None:
            return Result(ok=False, status_code=404, message="Article not found")

        db.session.execute(
            sa_delete(article_tags).where(
                article_tags.c.article_id == article_id,
                article_tags.c.tag_id == tag_id,
            )
        )
        db.session.commit()

        return Result(ok=True, status_code=200, data={"message": "Tag unbound successfully"})

    # --- Filtering ---

    @staticmethod
    def filter_by_tag_name(tag_name: str) -> Result:
        """Filter articles by tag name using a JOIN through the association table."""
        stmt = (
            select(Article)
            .join(article_tags, article_tags.c.article_id == Article.id)
            .join(Tag, Tag.id == article_tags.c.tag_id)
            .where(Tag.name == tag_name)
            .order_by(Article.id)
        )
        articles = db.session.execute(stmt).scalars().all()
        return Result(ok=True, status_code=200, data=_serialize_articles(articles))

    @staticmethod
    def filter_by_tag_id(tag_id: int) -> Result:
        """Filter articles by tag ID using a subquery on the association table.

        This variant uses a subquery approach (different from the JOIN used in
        filter_by_tag_name) to demonstrate alternative SQL composition.
        """
        matching_article_ids = db.session.scalars(
            select(article_tags.c.article_id).where(
                article_tags.c.tag_id == tag_id
            )
        ).all()

        if not matching_article_ids:
            return Result(ok=True, status_code=200, data=[])

        articles = db.session.scalars(
            select(Article)
            .where(Article.id.in_(matching_article_ids))
            .order_by(Article.id)
        ).all()
        return Result(ok=True, status_code=200, data=_serialize_articles(articles))


# Instantiate the service for use in route handlers
_svc = ArticleService()


# ---------------------------------------------------------------------------
# Route handlers -- thin adapters from HTTP to service layer
# ---------------------------------------------------------------------------

@article_bp.route("/articles", methods=["POST"])
def create_article():
    """POST /articles -- Create a new article."""
    payload = request.get_json(silent=True)
    v = Validator(payload)
    title = v.require_string("title")
    body = v.require_string("body")

