    # Insert new association rows (skip duplicates).
    for tag in tags:
        if tag not in article.tags:
            article.tags.append(tag)

    db.session.commit()
    return Result(
        ok=True,
        status_code=200,
        data={"message": f"Bound {len(tags)} tag(s) to article {article_id}"},
    )


