    tags = db.session.execute(
        select(Tag)
        .join(article_tags, Tag.id == article_tags.c.tag_id)
        .where(article_tags.c.article_id == article_id)
        .order_by(Tag.id)
    ).scalars().all()

    return Result(ok=True, status_code=200, data=[_serialize_tag(t) for t in tags])


