    db.session.execute(
        sa_delete(article_tags).where(
            article_tags.c.article_id == article_id,
            article_tags.c.tag_id == tag_id,
        )
    )
    db.session.commit()
    return Result(ok=True, status_code=200, data={"message": "Tag unbound from article"})


